from lxml import etree
import hashlib
import base64

# KeyInfo del XML firmado
xml = '''<ds:KeyInfo xmlns:ds="http://www.w3.org/2000/09/xmldsig#" Id="id21b3973755134e24be075c390eb733dc_73"><ds:X509Data><ds:X509Certificate></ds:X509Certificate></ds:X509Data></ds:KeyInfo>'''

# Parsear el KeyInfo
ki = etree.fromstring(xml.encode('utf-8'))

# Canonicalizar con Inclusive C14N
ki_c14n = etree.tostring(ki, method='c14n', exclusive=False, with_comments=False)

# Calcular digest SHA1
digest_calculado = base64.b64encode(hashlib.sha1(ki_c14n).digest()).decode()

# Digest que aparece en el XML
digest_en_xml = "fQe8kaGfvC9fQAv/Nr5KIBxGP4A="

print(f'✅ Digest calculado: {digest_calculado}')
print(f'📄 Digest en XML:    {digest_en_xml}')
print(f'{"✅ MATCH!" if digest_calculado == digest_en_xml else "❌ NO MATCH"}')

# Mostrar longitud C14N para debug
print(f'\n📊 Longitud C14N KeyInfo: {len(ki_c14n)} bytes')
print(f'📊 Primeros 100 bytes: {ki_c14n[:100]}')
